parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "title": {
      "type": "string"
    },
    "ideaText": {
      "type": "string"
    },
    "summary": {
      "type": "string"
    },
    "taxonomy": {
      "type": "object",
      "properties": {
        "type": {
          "type": "string",
          "enum": ["Type I", "Type II", "Type III", "Type IV"]
        },
        "title": {
          "type": "string",
          "enum": [
            "Deterministic Execution",
            "Structured Inference",
            "Bounded Language Intelligence",
            "Open-Ended Reasoning Workflow"
          ]
        },
        "reasoning": {
          "type": "string"
        }
      },
      "required": ["type", "title", "reasoning"],
      "additionalProperties": false
    },
    "dice": {
      "type": "object",
      "properties": {
        "determinism": { "type": "integer", "minimum": 1, "maximum": 5 },
        "inputComplexity": { "type": "integer", "minimum": 1, "maximum": 5 },
        "costOfError": { "type": "integer", "minimum": 1, "maximum": 5 },
        "economics": { "type": "integer", "minimum": 1, "maximum": 5 },
        "total": { "type": "integer", "minimum": 4, "maximum": 20 }
      },
      "required": ["determinism", "inputComplexity", "costOfError", "economics", "total"],
      "additionalProperties": false
    },
    "reliability": {
      "type": "object",
      "properties": {
        "requirement": { "type": "integer", "minimum": 1, "maximum": 5 },
        "stakes": { "type": "integer", "minimum": 1, "maximum": 5 },
        "quadrant": {
          "type": "string",
          "enum": [
            "High Reliability + Low Stakes",
            "Low Reliability + Low Stakes",
            "High Reliability + High Stakes",
            "Low Reliability + High Stakes"
          ]
        },
        "strategy": { "type": "string" }
      },
      "required": ["requirement", "stakes", "quadrant", "strategy"],
      "additionalProperties": false
    },
    "frameworks": {
      "type": "array",
      "minItems": 5,
      "maxItems": 5,
      "items": {
        "type": "object",
        "properties": {
          "key": { "type": "string" },
          "label": { "type": "string" },
          "score": { "type": "integer", "minimum": 0, "maximum": 100 },
          "summary": { "type": "string" }
        },
        "required": ["key", "label", "score", "summary"],
        "additionalProperties": false
      }
    },
    "route": {
      "type": "object",
      "properties": {
        "solver": {
          "type": "string",
          "enum": [
            "Deterministic software",
            "Classical ML scorecard",
            "Single-LLM pipeline with validators",
            "Agentic orchestration with a deterministic harness"
          ]
        },
        "decisionLabel": {
          "type": "string",
          "enum": [
            "REJECT",
            "DEFER",
            "APPROVE (Assistive)",
            "APPROVE (Constrained Autonomy)",
            "APPROVE (Autonomous)"
          ]
        },
        "automationLevel": {
          "type": "string",
          "enum": [
            "Deterministic only",
            "Classical ML first",
            "Assistive AI",
            "Constrained autonomy",
            "Autonomous agent"
          ]
        },
        "reasoning": { "type": "string" }
      },
      "required": ["solver", "decisionLabel", "automationLevel", "reasoning"],
      "additionalProperties": false
    },
    "conclusion": {
      "type": "string"
    },
    "buildRecommendation": {
      "type": "string"
    },
    "governanceNotes": {
      "type": "array",
      "minItems": 3,
      "maxItems": 3,
      "items": { "type": "string" }
    }
  },
  "required": [
    "title",
    "ideaText",
    "summary",
    "taxonomy",
    "dice",
    "reliability",
    "frameworks",
    "route",
    "conclusion",
    "buildRecommendation",
    "governanceNotes"
  ],
  "additionalProperties": false
}

parameters.jsCode:
const prep = $node['Prepare Gate Prompt'].json;
const raw = $node['AI Gate Evaluator'].json.output || $node['AI Gate Evaluator'].json;
const result = raw.output && typeof raw.output === 'object' ? raw.output : raw;

const ensureArray = (value) => Array.isArray(value) ? value : [];
const frameworks = ensureArray(result.frameworks).slice(0, 5).map((item, index) => ({
  key: String(item.key || ['taxonomy', 'dice', 'reliability', 'governance', 'automation'][index] || `framework_${index + 1}`),
  label: String(item.label || `Framework ${index + 1}`),
  score: Number.isFinite(Number(item.score)) ? Math.max(0, Math.min(100, Math.round(Number(item.score)))) : 50,
  summary: String(item.summary || '')
}));

const governanceNotes = ensureArray(result.governanceNotes).slice(0, 3).map((note) => String(note));
while (governanceNotes.length < 3) {
  governanceNotes.push('Add explicit monitoring and rollback criteria before launch.');
}

const dice = result.dice || {};
const total = Number(dice.determinism || 0) + Number(dice.inputComplexity || 0) + Number(dice.costOfError || 0) + Number(dice.economics || 0);

const finalResult = {
  title: String(result.title || prep.title),
  ideaText: String(result.ideaText || prep.ideaText),
  summary: String(result.summary || ''),
  taxonomy: result.taxonomy,
  dice: {
    determinism: Number(dice.determinism || 1),
    inputComplexity: Number(dice.inputComplexity || 1),
    costOfError: Number(dice.costOfError || 1),
    economics: Number(dice.economics || 1),
    total: Number.isFinite(Number(dice.total)) ? Number(dice.total) : total
  },
  reliability: result.reliability,
  frameworks,
  route: result.route,
  conclusion: String(result.conclusion || ''),
  buildRecommendation: String(result.buildRecommendation || ''),
  governanceNotes,
  simulated: false
};

return [{ json: finalResult }];
